    def _populate_algorithm_tree(self):
        self.algorithm_tree.clear()
        source_menus = [
            self.menuKlassik_usullar,
            self.menuKvant_usullar,
            self.menuBaholash,
            self.menuTasniflash_va_tanib_olish,
        ]
        for menu in source_menus:
            root = QtWidgets.QTreeWidgetItem([menu.title()])
            self.algorithm_tree.addTopLevelItem(root)
            self._add_menu_items(root, menu)
            root.setExpanded(True)

    def _add_menu_items(self, parent_item, menu):
        for action in menu.actions():
            if action.isSeparator():
                continue
            submenu = action.menu()
            if submenu is not None:
                child = QtWidgets.QTreeWidgetItem([submenu.title()])
                parent_item.addChild(child)
                self._add_menu_items(child, submenu)
                continue
            child = QtWidgets.QTreeWidgetItem([action.text()])
            child.setData(0, QtCore.Qt.UserRole, action.objectName())
            parent_item.addChild(child)

